20	export function runScenario(scenario: any): { results: unknown[] } {
21	  const results: unknown[] = [];
22	  let quoteCount = 0;
23	  const remainingCaps = new Map<number, number>();
24	  for (const step of scenario.steps) {
25	    if (step.op === "quote") {
26	      assertKnownItemTypes(step.items);
27	      const premium = quote({
28	        customer: {
29	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
30	          previousContracts: quoteCount,
31	        },
32	        items: step.items,
33	      });
34	      results.push({ premium });
35	      quoteCount++;
36	    } else if (step.op === "claim") {
37	      const policyStep = scenario.steps[step.policy];
38	      const policyItemTypes = policyStep.items.map(
39	        (item: { type: string }) => item.type,
40	      );
41	      for (const damage of step.incident.damages) {
42	        if (!policyItemTypes.includes(damage.itemType)) {
43	          throw new Error(
44	            `Claim damages an item not in policy: ${damage.itemType}`,
45	          );
46	        }
47	      }
48	      const { payout, remainingCap } = claim({
49	        items: policyStep.items,
50	        incident: step.incident,
51	        remainingCap: remainingCaps.get(step.policy),
52	      });
53	      remainingCaps.set(step.policy, remainingCap);
54	      results.push({ payout, remainingCap });
55	    }
56	  }
57	  return { results };
58	}
